  1→// Types matching the Rust backend serialization
  2→
  3→export interface DisplayMessage {
  4→  role: "user" | "claude" | "system" | "compact";
  5→  model: string;
  6→  content: string;
  7→  timestamp: string;
  8→  thinking_count: number;
  9→  tool_call_count: number;
 10→  output_count: number;
 11→  tokens_raw: number;
 12→  input_tokens: number;
 13→  output_tokens: number;
 14→  cache_read_tokens: number;
 15→  cache_creation_tokens: number;
 16→  context_tokens: number;
 17→  duration_ms: number;
 18→  items: DisplayItem[];
 19→  last_output: LastOutput | null;
 20→  is_error: boolean;
 21→  teammate_spawns: number;
 22→  teammate_messages: number;
 23→  subagent_label: string;
 24→}
 25→
 26→export type DisplayItemType =
 27→  | "Thinking"
 28→  | "Output"
 29→  | "ToolCall"
 30→  | "Subagent"
 31→  | "TeammateMessage"
 32→  | "HookEvent";
 33→
 34→export interface DisplayItem {
 35→  item_type: DisplayItemType;
 36→  text: string;
 37→  tool_name: string;
 38→  tool_summary: string;
 39→  tool_category: string;
 40→  tool_input: string;
 41→  tool_result: string;
 42→  tool_error: boolean;
 43→  duration_ms: number;
 44→  token_count: number;
 45→  subagent_type: string;
 46→  subagent_desc: string;
 47→  subagent_prompt: string;
 48→  team_member_name: string;
 49→  teammate_id: string;
 50→  team_color: string;
 51→  subagent_ongoing: boolean;
 52→  agent_id: string;
 53→  subagent_messages: DisplayMessage[];
 54→  hook_event: string;
 55→  hook_name: string;
 56→  hook_command: string;
 57→  is_orphan: boolean;
 58→}
 59→
 60→export interface LastOutput {
 61→  output_type: "Text" | "ToolResult" | "ToolCalls";
 62→  text: string;
 63→  tool_name: string;
 64→  tool_result: string;
 65→  is_error: boolean;
 66→  tool_calls: ToolCallSummary[];
 67→}
 68→
 69→export interface ToolCallSummary {
 70→  name: string;
 71→  summary: string;
 72→}
 73→
 74→export interface SessionInfo {
 75→  path: string;
 76→  session_id: string;
 77→  mod_time: string;
 78→  first_message: string;
 79→  turn_count: number;
 80→  is_ongoing: boolean;
 81→  total_tokens: number;
 82→  input_tokens: number;
 83→  output_tokens: number;
 84→  cache_read_tokens: number;
 85→  cache_creation_tokens: number;
 86→  cost_usd: number;
 87→  duration_ms: number;
 88→  model: string;
 89→  cwd: string;
 90→  git_branch: string;
 91→  permission_mode: string;
 92→}
 93→
 94→export interface SessionMeta {
 95→  cwd: string;
 96→  git_branch: string;
 97→  permission_mode: string;
 98→}
 99→
100→export interface TeamSnapshot {
101→  name: string;
102→  description: string;
103→  tasks: TeamTask[];
104→  members: string[];
105→  member_colors: Record<string, string>;
106→  member_ongoing: Record<string, boolean>;
107→  deleted: boolean;
108→}
109→
110→export interface TeamTask {
111→  id: string;
112→  subject: string;
113→  status: string;
114→  owner: string;
115→}
116→
117→export interface DateGroup {
118→  category: string;
119→  sessions: SessionInfo[];
120→}
121→
122→export interface SessionTotals {
123→  total_tokens: number;
124→  input_tokens: number;
125→  output_tokens: number;
126→  cache_read_tokens: number;
127→  cache_creation_tokens: number;
128→  cost_usd: number;
129→  model: string;
130→}
131→
132→export interface LoadResult {
133→  messages: DisplayMessage[];
134→  teams: TeamSnapshot[];
135→  ongoing: boolean;
136→  meta: SessionMeta;
137→  session_totals: SessionTotals;
138→}
139→
140→export interface GitInfo {
141→  branch: string;
142→  dirty: boolean;
143→  worktree_dirs: string[];
144→}
145→
146→export interface DebugEntry {
147→  timestamp: string;
148→  level: string;
149→  category: string;
150→  message: string;
151→  extra: string;
152→  line_num: number;
153→  count: number;
154→}
155→
156→export type ViewState = "picker" | "list" | "detail" | "team" | "debug";
