  1→import { useState, useEffect, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import type {
  4→  DisplayMessage,
  5→  TeamSnapshot,
  6→  SessionMeta,
  7→  SessionTotals,
  8→  LoadResult,
  9→  GitInfo,
 10→  DebugEntry,
 11→} from "../types";
 12→import { useTauriEvent } from "./useTauriEvent";
 13→
 14→interface SessionState {
 15→  messages: DisplayMessage[];
 16→  teams: TeamSnapshot[];
 17→  ongoing: boolean;
 18→  meta: SessionMeta;
 19→  sessionTotals: SessionTotals;
 20→  sessionPath: string;
 21→  gitInfo: GitInfo | null;
 22→  debugEntries: DebugEntry[];
 23→  loading: boolean;
 24→}
 25→
 26→const emptyMeta: SessionMeta = {
 27→  cwd: "",
 28→  git_branch: "",
 29→  permission_mode: "",
 30→};
 31→
 32→const emptyTotals: SessionTotals = {
 33→  total_tokens: 0,
 34→  input_tokens: 0,
 35→  output_tokens: 0,
 36→  cache_read_tokens: 0,
 37→  cache_creation_tokens: 0,
 38→  cost_usd: 0,
 39→  model: "",
 40→};
 41→
 42→export function useSession() {
 43→  const [state, setState] = useState<SessionState>({
 44→    messages: [],
 45→    teams: [],
 46→    ongoing: false,
 47→    meta: emptyMeta,
 48→    sessionTotals: emptyTotals,
 49→    sessionPath: "",
 50→    gitInfo: null,
 51→    debugEntries: [],
 52→    loading: false,
 53→  });
 54→
 55→  const loadSession = useCallback(async (path: string) => {
 56→    setState((prev) => ({ ...prev, loading: true }));
 57→    try {
 58→      // Stop watching previous session
 59→      try {
 60→        await invoke<void>("unwatch_session");
 61→      } catch {
 62→        // ignore if no session was being watched
 63→      }
 64→
 65→      const result = await invoke<LoadResult>("load_session", { path });
 66→
 67→      // Extract git info from session cwd
 68→      let gitInfo: GitInfo | null = null;
 69→      if (result.meta.cwd) {
 70→        try {
 71→          gitInfo = await invoke<GitInfo>("get_git_info", {
 72→            cwd: result.meta.cwd,
 73→          });
 74→        } catch {
 75→          // git info is optional
 76→        }
 77→      }
 78→
 79→      setState({
 80→        messages: result.messages,
 81→        teams: result.teams,
 82→        ongoing: result.ongoing,
 83→        meta: result.meta,
 84→        sessionTotals: result.session_totals,
 85→        sessionPath: path,
 86→        gitInfo,
 87→        debugEntries: [],
 88→        loading: false,
 89→      });
 90→
 91→      // Start watching for updates
 92→      try {
 93→        await invoke<void>("watch_session", { path });
 94→      } catch {
 95→        // watcher is optional
 96→      }
 97→    } catch (err) {
 98→      console.error("Failed to load session:", err);
 99→      setState((prev) => ({ ...prev, loading: false }));
100→    }
101→  }, []);
102→
103→  const loadDebugLog = useCallback(async (sessionPath: string) => {
104→    try {
105→      const entries = await invoke<DebugEntry[]>("get_debug_log", {
106→        sessionPath,
107→      });
108→      setState((prev) => ({ ...prev, debugEntries: entries }));
109→    } catch (err) {
110→      console.error("Failed to load debug log:", err);
111→    }
112→  }, []);
113→
114→  // Listen for session-update events
115→  useTauriEvent<{
116→    messages: DisplayMessage[];
117→    teams: TeamSnapshot[];
118→    ongoing: boolean;
119→    permission_mode: string;
120→    session_totals: SessionTotals;
121→  }>("session-update", (payload) => {
122→    setState((prev) => ({
123→      ...prev,
124→      messages: payload.messages,
125→      teams: payload.teams,
126→      ongoing: payload.ongoing,
127→      sessionTotals: payload.session_totals,
128→      meta: {
129→        ...prev.meta,
130→        permission_mode: payload.permission_mode || prev.meta.permission_mode,
131→      },
132→    }));
133→  });
134→
135→  // Cleanup on unmount
136→  useEffect(() => {
137→    return () => {
138→      invoke<void>("unwatch_session").catch(() => {});
139→    };
140→  }, []);
141→
142→  return {
143→    ...state,
144→    loadSession,
145→    loadDebugLog,
146→  };
147→}
