199→              >
200→                {item.tool_result}
201→              </div>
202→            </div>
203→          )}
204→        </div>
205→      );
206→    case "Subagent":
207→      return (
208→        <div className="detail-item__body">
209→          {item.agent_id && (
210→            <div className="detail-item__section">
211→              <div className="detail-item__section-title">Agent ID</div>
212→              <div className="detail-item__text detail-item__text--mono">{item.agent_id}</div>
213→            </div>
214→          )}
215→          {item.subagent_desc && (
216→            <div className="detail-item__section">
217→              <div className="detail-item__section-title">Description</div>
218→              <div className="detail-item__text">{item.subagent_desc}</div>
219→            </div>
220→          )}
221→          {item.subagent_prompt && (
222→            <div className="detail-item__section">
223→              <div className="detail-item__section-title">Prompt</div>
224→              <div className="detail-item__text">{item.subagent_prompt}</div>
225→            </div>
226→          )}
227→          {item.text && (
228→            <div className="detail-item__section">
229→              <div className="detail-item__section-title">Content</div>
230→              <div className="detail-item__text">{item.text}</div>
231→            </div>
232→          )}
233→        </div>
234→      );
235→    case "TeammateMessage":
236→      return (
237→        <div className="detail-item__body">
238→          <div className="detail-item__text">{item.text}</div>
239→        </div>
240→      );
241→    case "HookEvent":
242→      return (
243→        <div className="detail-item__body">
244→          <div className="detail-item__section">
245→            <div className="detail-item__section-title">Hook</div>
246→            <div className="detail-item__text detail-item__text--mono">
247→              {item.hook_event}: {item.hook_name}
248→            </div>
249→          </div>
250→          {item.hook_command && (
251→            <div className="detail-item__section">
252→              <div className="detail-item__section-title">Command</div>
253→              <div className="detail-item__json">
254→                <pre>
255→                  <code>{item.hook_command}</code>
256→                </pre>
257→              </div>
258→            </div>
259→          )}
