  1→import { useState, useMemo, useCallback, useRef, useLayoutEffect, useEffect } from "react";
  2→import ReactMarkdown from "react-markdown";
  3→import type { DisplayMessage, DisplayItem } from "../types";
  4→import { shortModel, formatTokens, formatDuration, formatExactTime } from "../lib/format";
  5→import { getModelColor, getTeamColor } from "../lib/theme";
  6→import { MessageItem } from "./MessageItem";
  7→import { DetailItem } from "./DetailItem";
  8→import { useToggleSet } from "../hooks/useToggleSet";
  9→import { useScrollToSelected } from "../hooks/useScrollToSelected";
 10→import { useAutoScroll } from "../hooks/useAutoScroll";
 11→import { useKeyboard } from "../hooks/useKeyboard";
 12→import { BackButton } from "./BackButton";
 13→import { ResizeHandle } from "./ResizeHandle";
 14→import { OngoingDots } from "./OngoingDots";
 15→import { IoMdCloseCircle } from "react-icons/io";
 16→import { ClaudeIcon } from "./Icons";
 17→
 18→/* ─── Helpers ─── */
 19→
 20→/** Recursively find a DisplayItem by agent_id in a nested item tree. */
 21→function findItemByAgentId(items: DisplayItem[], agentId: string): DisplayItem | undefined {
 22→  for (const item of items) {
 23→    if (item.agent_id === agentId) return item;
 24→    for (const subMsg of item.subagent_messages) {
 25→      const found = findItemByAgentId(subMsg.items, agentId);
 26→      if (found) return found;
 27→    }
 28→  }
 29→  return undefined;
 30→}
 31→
 32→/* ─── Panel stack types ─── */
 33→
 34→type PanelEntry =
 35→  | { kind: "agent-list"; item: DisplayItem; key: string }
 36→  | { kind: "agent-detail"; item: DisplayItem; msg: DisplayMessage; key: string };
 37→
 38→/** Imperative handle exposed by each navigable column */
 39→interface ColumnNav {
 40→  moveUp: () => void;
 41→  moveDown: () => void;
 42→  toggle: () => void;
 43→  enter: () => void;
 44→  itemCount: () => number;
 45→}
 46→
 47→interface MessageDetailProps {
 48→  message: DisplayMessage;
 49→  ongoing?: boolean;
 50→  onBack: () => void;
 51→}
 52→
 53→export function MessageDetail({ message: msg, ongoing, onBack }: MessageDetailProps) {
 54→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
 55→  const [selectedItem, setSelectedItem] = useState(0);
 56→  const scrollRef = useScrollToSelected(selectedItem);
 57→  const [panelStack, setPanelStack] = useState<PanelEntry[]>([]);
 58→  const [columnWidths, setColumnWidths] = useState<(number | null)[]>([null]);
 59→  const [focusedColumn, setFocusedColumn] = useState(0); // 0 = main, 1+ = panel index + 1
 60→  const bodyRef = useRef<HTMLDivElement>(null);
 61→  useAutoScroll(msg.items.length, bodyRef);
 62→  const savedScroll = useRef<number | null>(null);
 63→  const panelRefs = useRef<Map<number, ColumnNav>>(new Map());
 64→
 65→  // Keep panel stack items fresh when the session watcher sends updated data.
 66→  // Without this, subagent_ongoing and subagent_messages would be stale.
 67→  // Only updates state when something meaningful changed to avoid extra re-renders.
 68→  useEffect(() => {
 69→    if (panelStack.length === 0) return;
 70→    setPanelStack((prev) => {
 71→      let changed = false;
 72→      const next = prev.map((entry) => {
 73→        if (!entry.item.agent_id) return entry;
 74→        const fresh = findItemByAgentId(msg.items, entry.item.agent_id);
 75→        if (!fresh) return entry;
 76→        // Skip if nothing meaningful changed.
 77→        if (
 78→          fresh.subagent_ongoing === entry.item.subagent_ongoing &&
 79→          fresh.subagent_messages.length === entry.item.subagent_messages.length
 80→        ) {
 81→          return entry;
 82→        }
 83→        changed = true;
 84→        if (entry.kind === "agent-list") {
 85→          return { ...entry, item: fresh };
 86→        }
 87→        // For agent-detail, also refresh the message by matching timestamp.
 88→        const freshMsg =
 89→          fresh.subagent_messages.find(
 90→            (m) => m.timestamp === entry.msg.timestamp && m.role === entry.msg.role,
 91→          ) ?? entry.msg;
 92→        return { ...entry, item: fresh, msg: freshMsg };
 93→      });
 94→      return changed ? next : prev;
 95→    });
 96→  }, [msg.items, panelStack.length]);
 97→
 98→  useLayoutEffect(() => {
 99→    if (savedScroll.current != null && bodyRef.current) {
100→      bodyRef.current.scrollTop = savedScroll.current;
101→      savedScroll.current = null;
102→    }
103→  }, [panelStack.length]);
104→
105→  const model = msg.model ? shortModel(msg.model) : "";
106→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
107→  const time = formatExactTime(msg.timestamp);
108→  const hasItems = msg.items.length > 0;
109→  const hasPanels = panelStack.length > 0;
110→
111→  // Stack manipulation
112→  const openSubagentFromMain = useCallback((item: DisplayItem) => {
113→    if (bodyRef.current) {
114→      savedScroll.current = bodyRef.current.scrollTop;
115→    }
116→    setPanelStack((prev) => {
117→      if (
118→        prev.length === 1 &&
119→        prev[0].kind === "agent-list" &&
120→        prev[0].item.agent_id === item.agent_id
121→      ) {
122→        return [];
123→      }
124→      return [{ kind: "agent-list", item, key: item.agent_id || `panel-0` }];
125→    });
126→    setColumnWidths((prev) => [prev[0]]);
127→    setFocusedColumn(1);
128→  }, []);
129→
130→  const openSubagentAt = useCallback((depth: number, item: DisplayItem) => {
131→    setPanelStack((prev) => {
132→      const next = prev.slice(0, depth + 1);
133→      next.push({ kind: "agent-list", item, key: item.agent_id || `panel-${depth + 1}` });
134→      return next;
135→    });
136→    setColumnWidths((prev) => prev.slice(0, depth + 2));
137→    setFocusedColumn(depth + 2);
138→  }, []);
139→
140→  const openDetailAt = useCallback((depth: number, detailMsg: DisplayMessage) => {
141→    setPanelStack((prev) => {
142→      const entry = prev[depth];
143→      if (!entry || entry.kind !== "agent-list") return prev;
144→      const next = prev.slice(0, depth);
145→      next.push({
146→        kind: "agent-detail",
147→        item: entry.item,
148→        msg: detailMsg,
149→        key: entry.key + ":detail",
150→      });
151→      return next;
152→    });
153→  }, []);
154→
155→  const backToListAt = useCallback((depth: number) => {
156→    setPanelStack((prev) => {
157→      const entry = prev[depth];
158→      if (!entry || entry.kind !== "agent-detail") return prev;
159→      const next = prev.slice(0, depth);
160→      next.push({
161→        kind: "agent-list",
162→        item: entry.item,
163→        key: entry.item.agent_id || `panel-${depth}`,
164→      });
165→      return next;
166→    });
167→  }, []);
168→
169→  const closeAt = useCallback((depth: number) => {
170→    setPanelStack((prev) => prev.slice(0, depth));
171→    setColumnWidths((prev) => prev.slice(0, depth + 1));
172→    setFocusedColumn((prev) => Math.min(prev, depth));
173→  }, []);
174→
175→  const setColumnWidth = useCallback((colIndex: number, width: number) => {
176→    setColumnWidths((prev) => {
177→      const next = [...prev];
178→      while (next.length <= colIndex) next.push(null);
179→      next[colIndex] = width;
180→      return next;
181→    });
182→  }, []);
183→
184→  const handleItemClick = (index: number, item: DisplayItem) => {
185→    setSelectedItem(index);
186→    setFocusedColumn(0);
187→    if (item.subagent_messages.length > 0) {
188→      openSubagentFromMain(item);
189→    } else {
190→      toggleItem(index);
191→    }
192→  };
193→
194→  const registerPanelNav = useCallback((depth: number, nav: ColumnNav | null) => {
195→    if (nav) {
196→      panelRefs.current.set(depth, nav);
197→    } else {
198→      panelRefs.current.delete(depth);
199→    }
200→  }, []);
201→
202→  // Single keyboard handler for all columns
203→  const detailKeyMap: Record<string, () => void> = {};
204→
205→  // Navigation: j/k/ArrowDown/ArrowUp/Tab/Enter dispatch to the focused column
206→  const moveDown = () => {
207→    if (focusedColumn === 0) {
208→      setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
209→    } else {
210→      const nav = panelRefs.current.get(focusedColumn - 1);
211→      nav?.moveDown();
212→    }
213→  };
214→  const moveUp = () => {
215→    if (focusedColumn === 0) {
216→      setSelectedItem((i) => Math.max(i - 1, 0));
217→    } else {
218→      const nav = panelRefs.current.get(focusedColumn - 1);
219→      nav?.moveUp();
220→    }
221→  };
222→  detailKeyMap["j"] = moveDown;
223→  detailKeyMap["ArrowDown"] = moveDown;
224→  detailKeyMap["k"] = moveUp;
225→  detailKeyMap["ArrowUp"] = moveUp;
226→  detailKeyMap["Tab"] = () => {
227→    if (focusedColumn === 0) {
228→      const item = msg.items[selectedItem];
229→      if (item) handleItemClick(selectedItem, item);
230→    } else {
231→      const nav = panelRefs.current.get(focusedColumn - 1);
232→      nav?.toggle();
233→    }
234→  };
235→  detailKeyMap["Enter"] = () => {
236→    if (focusedColumn === 0) {
237→      const item = msg.items[selectedItem];
238→      if (item && item.subagent_messages.length > 0) {
239→        openSubagentFromMain(item);
240→      } else if (item) {
241→        toggleItem(selectedItem);
242→      }
243→    } else {
244→      const nav = panelRefs.current.get(focusedColumn - 1);
245→      nav?.enter();
246→    }
247→  };
248→
249→  // h/l or ArrowLeft/ArrowRight to switch focused column
250→  detailKeyMap["h"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
251→  detailKeyMap["ArrowLeft"] = () => setFocusedColumn((c) => Math.max(0, c - 1));
252→  detailKeyMap["l"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
253→  detailKeyMap["ArrowRight"] = () => setFocusedColumn((c) => Math.min(panelStack.length, c + 1));
254→
255→  // q = go back to list
256→  detailKeyMap["q"] = onBack;
257→  // Escape = close rightmost panel, or go back
258→  detailKeyMap["Escape"] = () => {
259→    if (panelStack.length > 0) {
260→      closeAt(panelStack.length - 1);
261→    } else {
262→      onBack();
263→    }
264→  };
265→
266→  useKeyboard(detailKeyMap);
267→
268→  const mainWidthStyle =
269→    hasPanels && columnWidths[0]
270→      ? { flex: `0 0 ${columnWidths[0]}px`, maxWidth: columnWidths[0] }
271→      : undefined;
272→
273→  return (
274→    <div className={`message-detail${hasPanels ? " message-detail--split" : ""}`}>
275→      <div
276→        className={`message-detail__main${focusedColumn === 0 ? " message-detail__main--focused" : ""}`}
277→        style={mainWidthStyle}
278→        onClick={() => setFocusedColumn(0)}
279→      >
280→        <div className="message-detail__header">
281→          <BackButton onClick={onBack} />
282→          <span className="message-detail__title">
283→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
284→          </span>
285→          {model && (
286→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
287→          )}
288→          {msg.subagent_label && (
289→            <span className="detail-item__subagent-badge">{msg.subagent_label}</span>
290→          )}
291→          <span className="message-detail__meta">
292→            {time}
293→            {msg.tokens_raw > 0 && (
294→              <>
295→                {" "}
296→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
297→              </>
298→            )}
299→            {msg.duration_ms > 0 && (
300→              <>
301→                {" "}
302→                {"\u00B7"} {formatDuration(msg.duration_ms)}
303→              </>
304→            )}
305→          </span>
306→        </div>
307→
308→        <div className="message-detail__body" ref={bodyRef}>
309→          <div className="message-detail__content">
310→            {msg.content && (
311→              <div className="message-detail__text">
312→                <ReactMarkdown>{msg.content}</ReactMarkdown>
313→              </div>
314→            )}
315→            {hasItems && (
316→              <div className="detail-items">
317→                <div className="detail-items__section-label">Items ({msg.items.length})</div>
318→                {msg.items.map((item, idx) => (
319→                  <DetailItem
320→                    key={`${item.item_type}-${item.tool_name}-${item.tool_summary}-${item.duration_ms}`}
321→                    ref={idx === selectedItem ? scrollRef : undefined}
322→                    item={item}
323→                    index={idx}
324→                    isSelected={idx === selectedItem}
325→                    isExpanded={expandedItems.has(idx)}
326→                    isAgentActive={
327→                      panelStack.length > 0 &&
328→                      panelStack[0].item.agent_id === item.agent_id &&
329→                      !!item.agent_id
330→                    }
331→                    onToggle={handleItemClick}
332→                    onToggleExpand={toggleItem}
333→                    onSelect={setSelectedItem}
334→                  />
335→                ))}
336→              </div>
337→            )}
338→            {ongoing && (
339→              <div className="message-detail__ongoing">
340→                <OngoingDots />
341→              </div>
342→            )}
343→          </div>
344→        </div>
345→      </div>
346→
347→      {panelStack.map((entry, depth) => {
348→        const colWidth = columnWidths[depth + 1];
349→        const widthStyle = colWidth ? { flex: `0 0 ${colWidth}px`, maxWidth: colWidth } : undefined;
350→        const isFocused = focusedColumn === depth + 1;
351→
352→        return (
353→          <PanelColumn
354→            key={entry.key}
355→            entry={entry}
356→            depth={depth}
357→            style={widthStyle}
358→            isFocused={isFocused}
359→            panelStack={panelStack}
360→            onOpenDetail={(detailMsg) => openDetailAt(depth, detailMsg)}
361→            onBackToList={() => backToListAt(depth)}
362→            onOpenSubagent={(item) => openSubagentAt(depth, item)}
363→            onClose={() => closeAt(depth)}
364→            onResize={(w) => setColumnWidth(depth, w)}
365→            onFocus={() => setFocusedColumn(depth + 1)}
366→            onRegisterNav={(nav) => registerPanelNav(depth, nav)}
367→          />
368→        );
369→      })}
370→    </div>
371→  );
372→}
373→
374→/* ─── PanelColumn: renders ResizeHandle + either list or detail ─── */
375→
376→interface PanelColumnProps {
377→  entry: PanelEntry;
378→  depth: number;
379→  style?: React.CSSProperties;
380→  isFocused: boolean;
381→  panelStack: PanelEntry[];
382→  onOpenDetail: (msg: DisplayMessage) => void;
383→  onBackToList: () => void;
384→  onOpenSubagent: (item: DisplayItem) => void;
385→  onClose: () => void;
386→  onResize: (width: number) => void;
387→  onFocus: () => void;
388→  onRegisterNav: (nav: ColumnNav | null) => void;
389→}
390→
391→function PanelColumn({
392→  entry,
393→  depth,
394→  style,
395→  isFocused,
396→  panelStack,
397→  onOpenDetail,
398→  onBackToList,
399→  onOpenSubagent,
400→  onClose,
401→  onResize,
402→  onFocus,
403→  onRegisterNav,
404→}: PanelColumnProps) {
405→  return (
406→    <>
407→      <ResizeHandle onResize={onResize} />
408→      {entry.kind === "agent-list" ? (
409→        <AgentListColumn
410→          item={entry.item}
411→          style={style}
412→          isFocused={isFocused}
413→          onOpenDetail={onOpenDetail}
414→          onClose={onClose}
415→          onFocus={onFocus}
416→          onRegisterNav={onRegisterNav}
417→        />
418→      ) : (
419→        <AgentDetailColumn
420→          item={entry.item}
421→          msg={entry.msg}
422→          style={style}
423→          isFocused={isFocused}
424→          depth={depth}
425→          panelStack={panelStack}
426→          onOpenSubagent={onOpenSubagent}
427→          onBack={onBackToList}
428→          onClose={onClose}
429→          onFocus={onFocus}
430→          onRegisterNav={onRegisterNav}
431→        />
432→      )}
433→    </>
434→  );
435→}
436→
437→/* ─── AgentListColumn: shows agent header + message list ─── */
438→
439→interface AgentListColumnProps {
440→  item: DisplayItem;
441→  style?: React.CSSProperties;
442→  isFocused: boolean;
443→  onOpenDetail: (msg: DisplayMessage) => void;
444→  onClose: () => void;
445→  onFocus: () => void;
446→  onRegisterNav: (nav: ColumnNav | null) => void;
447→}
448→
449→function AgentListColumn({
450→  item,
451→  style,
452→  isFocused,
453→  onOpenDetail,
454→  onClose,
455→  onFocus,
456→  onRegisterNav,
457→}: AgentListColumnProps) {
458→  const messages = item.subagent_messages;
459→  const [selectedMsg, setSelectedMsg] = useState(messages.length - 1);
460→  const { set: expandedSet, toggle: toggleMsg } = useToggleSet();
461→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
462→  const selectedRef = useScrollToSelected(selectedMsg);
463→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
464→
465→  const handleClick = useCallback(
466→    (index: number) => {
467→      onFocus();
468→      if (selectedMsg === index) {
469→        toggleMsg(index);
470→      } else {
471→        setSelectedMsg(index);
472→      }
473→    },
474→    [selectedMsg, toggleMsg, onFocus],
475→  );
476→
477→  // Expose navigation to parent via callback ref
478→  const navRef = useRef<ColumnNav>({
479→    moveUp: () => setSelectedMsg((i) => Math.max(i - 1, 0)),
480→    moveDown: () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1)),
481→    toggle: () => toggleMsg(selectedMsg),
482→    enter: () => {
483→      if (messages[selectedMsg]) onOpenDetail(messages[selectedMsg]);
484→    },
485→    itemCount: () => messages.length,
486→  });
487→  navRef.current.moveUp = () => setSelectedMsg((i) => Math.max(i - 1, 0));
488→  navRef.current.moveDown = () => setSelectedMsg((i) => Math.min(i + 1, messages.length - 1));
489→  navRef.current.toggle = () => toggleMsg(selectedMsg);
490→  navRef.current.enter = () => {
