573→function AgentDetailColumn({
574→  item,
575→  msg,
576→  style,
577→  isFocused,
578→  depth,
579→  panelStack,
580→  onOpenSubagent,
581→  onBack,
582→  onClose,
583→  onFocus,
584→  onRegisterNav,
585→}: AgentDetailColumnProps) {
586→  const { set: expandedItems, toggle: toggleItem } = useToggleSet();
587→  const [selectedItem, setSelectedItem] = useState(0);
588→  const scrollRef = useScrollToSelected(selectedItem);
589→  const detailBodyRef = useAutoScroll<HTMLDivElement>(msg.items.length);
590→  const panelColor = item.team_color ? getTeamColor(item.team_color) : undefined;
591→
592→  const model = msg.model ? shortModel(msg.model) : "";
593→  const modelColor = msg.model ? getModelColor(msg.model) : undefined;
594→  const time = formatExactTime(msg.timestamp);
595→  const hasItems = msg.items.length > 0;
596→
597→  // Check if a deeper panel is open for a given agent_id
598→  const activeAgentId = depth + 1 < panelStack.length ? panelStack[depth + 1].item.agent_id : null;
599→
600→  const handleItemClick = (index: number, clickedItem: DisplayItem) => {
601→    onFocus();
602→    setSelectedItem(index);
603→    if (clickedItem.subagent_messages.length > 0) {
604→      onOpenSubagent(clickedItem);
605→    } else {
606→      toggleItem(index);
607→    }
608→  };
609→
610→  // Expose navigation to parent via callback ref
611→  const navRef = useRef<ColumnNav>({
612→    moveUp: () => {},
613→    moveDown: () => {},
614→    toggle: () => {},
615→    enter: () => {},
616→    itemCount: () => msg.items.length,
617→  });
618→  navRef.current.moveUp = () => setSelectedItem((i) => Math.max(i - 1, 0));
619→  navRef.current.moveDown = () => setSelectedItem((i) => Math.min(i + 1, msg.items.length - 1));
620→  navRef.current.toggle = () => {
621→    const it = msg.items[selectedItem];
622→    if (it) handleItemClick(selectedItem, it);
623→  };
624→  navRef.current.enter = () => {
625→    const it = msg.items[selectedItem];
626→    if (it && it.subagent_messages.length > 0) {
627→      onOpenSubagent(it);
628→    } else if (it) {
629→      toggleItem(selectedItem);
630→    }
631→  };
632→  navRef.current.itemCount = () => msg.items.length;
633→
634→  useLayoutEffect(() => {
635→    onRegisterNav(navRef.current);
636→    return () => onRegisterNav(null);
637→  }, [onRegisterNav]);
638→
639→  return (
640→    <div
641→      className={`agent-panel${isFocused ? " agent-panel--focused" : ""}`}
642→      style={
643→        {
644→          ...(panelColor ? { background: `${panelColor}08` } : {}),
645→          ...style,
646→        } as React.CSSProperties
647→      }
648→      onClick={onFocus}
649→    >
650→      <AgentPanelHeader item={item} panelColor={panelColor} onClose={onClose} />
651→      <div className="agent-panel__content">
652→        <div className="message-detail__header" style={{ borderBottom: "1px solid var(--border)" }}>
653→          <BackButton onClick={onBack} />
654→          <span className="message-detail__title">
655→            {msg.role === "user" ? "User" : msg.role === "claude" ? "Claude" : "System"}
656→          </span>
657→          {model && (
658→            <span style={{ color: modelColor, fontWeight: 600, fontSize: 12 }}>{model}</span>
659→          )}
660→          <span className="message-detail__meta">
661→            {time}
662→            {msg.tokens_raw > 0 && (
663→              <>
664→                {" "}
665→                {"\u00B7"} {formatTokens(msg.tokens_raw)} tok
666→              </>
667→            )}
668→          </span>
669→        </div>
670→        <div className="message-detail__body" ref={detailBodyRef}>
671→          <div className="message-detail__content">
672→            {msg.content && (
673→              <div className="message-detail__text">
