 70→impl Entry {
 71→    /// Parse tool_use_result as a JSON object (map). Returns None if absent/non-object.
 72→    pub fn tool_use_result_map(&self) -> Option<HashMap<String, Value>> {
 73→        let val = self.tool_use_result.as_ref()?;
 74→        match val {
 75→            Value::Object(map) => {
 76→                let mut result = HashMap::new();
 77→                for (k, v) in map {
 78→                    result.insert(k.clone(), v.clone());
 79→                }
 80→                Some(result)
 81→            }
 82→            _ => None,
 83→        }
 84→    }
 85→}
