 13→/// Per-requestId token snapshot used for deduplication across JSONL files.
 14→#[derive(Clone)]
 15→pub struct TokenSnapshot {
 16→    pub input: i64,
 17→    pub output: i64,
 18→    pub cache_read: i64,
 19→    pub cache_create: i64,
 20→    pub model: String,
 21→    /// Whether the response completed (has a stop_reason).
 22→    /// Entries without stop_reason are partial streaming snapshots whose
 23→    /// output_tokens may be understated.
 24→    pub has_stop_reason: bool,
 25→}
 26→
 27→/// Pricing per million tokens for a model family.
 28→struct ModelPricing {
 29→    input: f64,
 30→    output: f64,
 31→    cache_read: f64,
 32→    cache_write: f64,
 33→}
 34→
 35→fn pricing_for_model(model: &str) -> ModelPricing {
 36→    let m = model.to_lowercase();
 37→    if m.contains("opus") {
 38→        ModelPricing {
 39→            input: 5.0,
 40→            output: 25.0,
 41→            cache_read: 0.5,
 42→            cache_write: 6.25,
 43→        }
 44→    } else if m.contains("haiku") {
 45→        ModelPricing {
 46→            input: 1.0,
 47→            output: 5.0,
 48→            cache_read: 0.1,
 49→            cache_write: 1.25,
 50→        }
 51→    } else {
 52→        // Default to sonnet
 53→        ModelPricing {
 54→            input: 3.0,
 55→            output: 15.0,
 56→            cache_read: 0.3,
 57→            cache_write: 3.75,
 58→        }
 59→    }
 60→}
 61→
 62→/// Insert a token snapshot, preferring entries with stop_reason (complete responses)
 63→/// over partial streaming snapshots with understated output_tokens.
 64→pub fn insert_best_snapshot(
 65→    map: &mut HashMap<String, TokenSnapshot>,
 66→    key: String,
 67→    snap: TokenSnapshot,
 68→) {
 69→    match map.get(&key) {
 70→        Some(existing) => {
 71→            // Prefer complete entries (has_stop_reason) over partial ones.
 72→            // Among same completeness, prefer higher output (later streaming = more tokens).
 73→            if (!existing.has_stop_reason && snap.has_stop_reason)
 74→                || (existing.has_stop_reason == snap.has_stop_reason
 75→                    && snap.output >= existing.output)
 76→            {
 77→                map.insert(key, snap);
 78→            }
 79→        }
 80→        None => {
 81→            map.insert(key, snap);
 82→        }
 83→    }
 84→}
 85→
 86→/// Estimate output tokens from assistant message content character count.
 87→/// Returns 0 if estimation is not possible.
 88→pub fn estimate_output_from_content(raw: &serde_json::Value) -> i64 {
 89→    let content = match raw.get("message").and_then(|m| m.get("content")) {
 90→        Some(c) => c,
 91→        None => return 0,
 92→    };
 93→    let arr = match content.as_array() {
 94→        Some(a) => a,
 95→        None => return 0,
 96→    };
 97→
 98→    let mut total_chars: i64 = 0;
 99→    for block in arr {
100→        let btype = block.get("type").and_then(|v| v.as_str()).unwrap_or("");
101→        match btype {
102→            "text" => {
103→                if let Some(t) = block.get("text").and_then(|v| v.as_str()) {
104→                    total_chars += t.len() as i64;
105→                }
106→            }
107→            "thinking" => {
108→                if let Some(t) = block.get("thinking").and_then(|v| v.as_str()) {
109→                    total_chars += t.len() as i64;
110→                }
111→            }
112→            "tool_use" => {
113→                // tool_use name + JSON input serialization
114→                total_chars += 20; // name overhead
115→                if let Some(input) = block.get("input") {
116→                    total_chars += input.to_string().len() as i64;
117→                }
118→            }
119→            _ => {}
120→        }
121→    }
122→    // Rough estimate: ~4 characters per token for English text/code.
123→    total_chars / 4
124→}
