126→/// Compute cost in USD from a set of token snapshots, pricing each by its model.
127→pub fn estimate_cost_from_snapshots(
128→    request_tokens: &std::collections::HashMap<String, TokenSnapshot>,
129→    fallback: &TokenSnapshot,
130→) -> f64 {
131→    let mut cost = 0.0;
132→
133→    // Fallback tokens (no requestId) — use fallback.model for pricing.
134→    if fallback.input + fallback.output + fallback.cache_read + fallback.cache_create > 0 {
135→        let p = pricing_for_model(&fallback.model);
136→        cost += (fallback.input as f64 * p.input
137→            + fallback.output as f64 * p.output
138→            + fallback.cache_read as f64 * p.cache_read
139→            + fallback.cache_create as f64 * p.cache_write)
140→            / 1_000_000.0;
141→    }
142→
143→    for snap in request_tokens.values() {
144→        let p = pricing_for_model(&snap.model);
145→        cost += (snap.input as f64 * p.input
146→            + snap.output as f64 * p.output
147→            + snap.cache_read as f64 * p.cache_read
148→            + snap.cache_create as f64 * p.cache_write)
149→            / 1_000_000.0;
150→    }
151→    cost
152→}
