284→/// Build a SubagentProcess from parsed chunks and file metadata.
285→fn build_subagent_process(
286→    id: String,
287→    file_path: String,
288→    metadata: &std::fs::Metadata,
289→    chunks: Vec<Chunk>,
290→    subagent_type: String,
291→    team_summary: String,
292→    teammate_color: String,
293→) -> SubagentProcess {
294→    let (start_time, end_time, duration_ms) = chunk_timing(&chunks);
295→    let usage = aggregate_usage(&chunks);
296→    let file_mod_time = metadata
297→        .modified()
298→        .ok()
299→        .map(DateTime::<Utc>::from)
300→        .unwrap_or_else(Utc::now);

300→        .unwrap_or_else(Utc::now);
301→    let prompt = first_user_text(&chunks);
302→
303→    SubagentProcess {
304→        id,
305→        file_path,
306→        file_mod_time,
307→        chunks,
308→        start_time,
309→        end_time,
310→        duration_ms,
311→        usage,
312→        subagent_type,
313→        team_summary,
314→        teammate_color,
315→        prompt,
316→        ..Default::default()
317→    }
318→}
