333→fn is_warmup_agent(path: &str) -> bool {
334→    let f = match fs::File::open(path) {
335→        Ok(f) => f,
336→        Err(_) => return false,
337→    };
338→    let reader = BufReader::new(f);
339→    for line_result in reader.lines() {
340→        let line = match line_result {
341→            Ok(l) => l,
342→            Err(_) => break,
343→        };
344→        let raw: serde_json::Value = match serde_json::from_str(&line) {
345→            Ok(v) => v,
346→            Err(_) => continue,
347→        };
348→        let entry_type = raw.get("type").and_then(|v| v.as_str()).unwrap_or("");
349→        if entry_type != "user" {
350→            continue;
351→        }
352→        let content = raw
353→            .get("message")
354→            .and_then(|m| m.get("content"))
355→            .and_then(|c| c.as_str())
356→            .unwrap_or("");
357→        return content == "Warmup";
358→    }
359→    false
360→}
361→
362→fn read_subagent_session(path: &str) -> Result<(Vec<Chunk>, String, String), String> {
363→    use super::patterns::{TEAMMATE_COLOR_RE, TEAMMATE_SUMMARY_RE};
364→
365→    let f = fs::File::open(path).map_err(|e| format!("opening {path}: {e}"))?;
366→    let reader = BufReader::new(f);
367→
368→    let mut msgs = Vec::new();
369→    let mut team_summary = String::new();
370→    let mut team_color = String::new();
371→    let mut extracted_team_meta = false;
372→
373→    for line_result in reader.lines() {
374→        let line = match line_result {
375→            Ok(l) => l,
376→            Err(_) => break,
377→        };
378→
379→        let mut entry = match parse_entry(line.as_bytes()) {
380→            Some(e) => e,
381→            None => continue,
382→        };
383→
384→        // Extract team metadata from first user entry.
385→        if !extracted_team_meta && entry.entry_type == "user" {
386→            if let Some(content) = &entry.message.content {
387→                if let Some(s) = content.as_str() {
388→                    if let Some(caps) = TEAMMATE_SUMMARY_RE.captures(s) {
389→                        team_summary = caps.get(1).map_or("", |m| m.as_str()).to_string();
390→                    }
391→                    if let Some(caps) = TEAMMATE_COLOR_RE.captures(s) {
392→                        team_color = caps.get(1).map_or("", |m| m.as_str()).to_string();
393→                    }
394→                    extracted_team_meta = true;
395→                }
396→            }
397→        }
398→
399→        // Clear sidechain flag so classify doesn't filter.
400→        entry.is_sidechain = false;
401→        if let Some(msg) = classify(entry) {
402→            msgs.push(msg);
403→        }
404→    }
405→
406→    Ok((build_chunks(&msgs), team_summary, team_color))
407→}
