409→fn chunk_timing(chunks: &[Chunk]) -> (DateTime<Utc>, DateTime<Utc>, i64) {
410→    let mut start: Option<DateTime<Utc>> = None;
411→    let mut end: Option<DateTime<Utc>> = None;
412→
413→    for c in chunks {
414→        if start.is_none() || c.timestamp < *start.as_ref().unwrap() {
415→            start = Some(c.timestamp);
416→        }
417→        if end.is_none() || c.timestamp > *end.as_ref().unwrap() {
418→            end = Some(c.timestamp);
419→        }
420→    }
421→
422→    let s = start.unwrap_or_else(Utc::now);
423→    let e = end.unwrap_or(s);
424→    let dur = e.signed_duration_since(s).num_milliseconds();
425→    (s, e, dur)
426→}
