428→fn aggregate_usage(chunks: &[Chunk]) -> Usage {
429→    for c in chunks.iter().rev() {
430→        if c.chunk_type == ChunkType::AI && c.usage.total_tokens() > 0 {
431→            return c.usage.clone();
432→        }
433→    }
434→    Usage::default()
435→}
