687→struct AgentLinkData {
688→    agent_to_tool_id: HashMap<String, String>,
689→    tool_id_to_color: HashMap<String, String>,
690→}
691→
692→fn scan_agent_links(session_path: &str) -> AgentLinkData {
693→    let mut data = AgentLinkData {
694→        agent_to_tool_id: HashMap::new(),
695→        tool_id_to_color: HashMap::new(),
696→    };
697→
698→    let f = match fs::File::open(session_path) {
699→        Ok(f) => f,

 700→        Err(_) => return data,
 701→    };
 702→    let reader = BufReader::new(f);
 703→
 704→    for line_result in reader.lines() {
 705→        let line = match line_result {
 706→            Ok(l) => l,
 707→            Err(_) => break,
 708→        };
 709→        let entry = match parse_entry(line.as_bytes()) {
 710→            Some(e) => e,
 711→            None => continue,
 712→        };
 713→        let result_map = match entry.tool_use_result_map() {
 714→            Some(m) => m,
 715→            None => continue,
 716→        };
 717→
 718→        let agent_id = result_map
 719→            .get("agentId")
 720→            .or_else(|| result_map.get("agent_id"))
 721→            .and_then(|v| v.as_str())
 722→            .unwrap_or("")
 723→            .to_string();
 724→        if agent_id.is_empty() {
 725→            continue;
 726→        }
 727→
 728→        let mut tool_use_id = entry.source_tool_use_id.clone();
 729→        if tool_use_id.is_empty() {
