 889→fn read_team_session_meta(path: &str) -> (String, String) {
 890→    let f = match fs::File::open(path) {
 891→        Ok(f) => f,
 892→        Err(_) => return (String::new(), String::new()),
 893→    };
 894→    let reader = BufReader::new(f);
 895→    for line_result in reader.lines() {
 896→        let line = match line_result {
 897→            Ok(l) => l,
 898→            Err(_) => break,
 899→        };
 900→        let raw: serde_json::Value = match serde_json::from_str(&line) {
 901→            Ok(v) => v,
 902→            Err(_) => continue,
 903→        };
 904→        let team_name = raw
 905→            .get("teamName")
 906→            .and_then(|v| v.as_str())
 907→            .unwrap_or("")
 908→            .to_string();
 909→        let agent_name = raw
 910→            .get("agentName")
 911→            .and_then(|v| v.as_str())
 912→            .unwrap_or("")
 913→            .to_string();
 914→        return (team_name, agent_name);
 915→    }
 916→    (String::new(), String::new())
 917→}
