 919→/// Extract (team_name, agent_name) pairs from Task items in parent chunks.
 920→fn extract_team_specs(chunks: &[Chunk]) -> Vec<(String, String)> {
 921→    let mut specs = Vec::new();
 922→    for c in chunks {
 923→        if c.chunk_type != ChunkType::AI {
 924→            continue;
 925→        }
 926→        for item in &c.items {
 927→            if item.item_type != DisplayItemType::Subagent || !is_team_task(item) {
 928→                continue;
 929→            }
 930→            if let Some(Value::Object(map)) = &item.tool_input {
 931→                let tn = map.get("team_name").and_then(|v| v.as_str()).unwrap_or("");
 932→                let an = map.get("name").and_then(|v| v.as_str()).unwrap_or("");
 933→                if !tn.is_empty() && !an.is_empty() {
 934→                    specs.push((tn.to_string(), an.to_string()));
 935→                }
 936→            }
 937→        }
 938→    }
 939→    specs
 940→}
