 942→/// Resolve the subagents directory for a session file path.
 943→pub fn subagents_dir(session_path: &str) -> std::path::PathBuf {
 944→    let dir = Path::new(session_path).parent().unwrap_or(Path::new(""));
 945→    let base = Path::new(session_path)
 946→        .file_stem()
 947→        .and_then(|s| s.to_str())
 948→        .unwrap_or("");
 949→    dir.join(base).join("subagents")
 950→}
